mapper.select:
select sum(powerConsumption) powerConsumption,a.`hour` from (
SELECT date_format(a.upload_time, '%H' ) `hour`, ABS(a.`value` - b.`value`) AS powerConsumption,a.upload_time FROM ( select a.`name`,a.`value`,a.upload_time,a.unique_id from tunnel_power_data a JOIN ( select DATE_FORMAT(upload_time, '%Y-%m-%d %H') AS hour_group,MAX(upload_time) upload_time,unique_id from tunnel_power_data where `name`='IMPEP' and upload_time >= DATE_SUB(#{nowDate},INTERVAL 1 DAY) AND unique_id in
#{ascUniqueId}
AND upload_time <= CONCAT(#{nowDate},' 23:59:59') GROUP BY date_format(upload_time, '%Y-%m-%d %H' ),unique_id ORDER BY upload_time desc ) b ON DATE_FORMAT(a.upload_time, '%Y-%m-%d %H') = b.hour_group AND a.upload_time = b.upload_time and `name` = 'impep' and a.unique_id = b.unique_id AND a.unique_id in
#{ascUniqueId}
order by a.upload_time desc ) a JOIN ( select a.`name`,a.`value`,a.upload_time,a.unique_id from tunnel_power_data a JOIN ( select DATE_FORMAT(upload_time, '%Y-%m-%d %H') AS hour_group,MAX(upload_time) upload_time,unique_id from tunnel_power_data where `name`='IMPEP' and upload_time >= DATE_SUB(#{nowDate},INTERVAL 1 DAY) AND unique_id in
#{ascUniqueId}
AND upload_time <= CONCAT(#{nowDate},' 23:59:59') GROUP BY date_format(upload_time, '%Y-%m-%d %H' ),unique_id ORDER BY upload_time desc ) b ON DATE_FORMAT(a.upload_time, '%Y-%m-%d %H') = b.hour_group AND a.upload_time = b.upload_time and `name` = 'impep' and a.unique_id = b.unique_id AND a.unique_id in
#{ascUniqueId}
order by a.upload_time desc ) b ON CONCAT(date_format(a.upload_time, '%Y-%m-%d %H' ),':00:00') = DATE_ADD(CONCAT(date_format(b.upload_time, '%Y-%m-%d %H' ),':00:00'), INTERVAL 1 HOUR) and a.unique_id = b.unique_id where DATE(a.upload_time) = #{nowDate}
union all SELECT date_format(a.upload_time, '%H' ) `hour`, ABS(a.`value` - b.`value`) AS powerConsumption,a.upload_time FROM ( select a.`name`,a.`value`,a.upload_time,a.unique_id from tunnel_power_data a JOIN ( select DATE_FORMAT(upload_time, '%Y-%m-%d %H') AS hour_group,MAX(upload_time) upload_time,unique_id from tunnel_power_data where `name`='IMPEP' and upload_time >= DATE_SUB(#{nowDate},INTERVAL 1 DAY) AND unique_id in
#{descUniqueId}
AND upload_time <= CONCAT(#{nowDate},' 23:59:59') GROUP BY date_format(upload_time, '%Y-%m-%d %H' ),unique_id ORDER BY upload_time desc ) b ON DATE_FORMAT(a.upload_time, '%Y-%m-%d %H') = b.hour_group AND a.upload_time = b.upload_time and `name` = 'impep' and a.unique_id = b.unique_id AND a.unique_id in
#{descUniqueId}
order by a.upload_time desc ) a JOIN ( select a.`name`,a.`value`,a.upload_time,a.unique_id from tunnel_power_data a JOIN ( select DATE_FORMAT(upload_time, '%Y-%m-%d %H') AS hour_group,MAX(upload_time) upload_time,unique_id from tunnel_power_data where `name`='IMPEP' and upload_time >= DATE_SUB(#{nowDate},INTERVAL 1 DAY) AND unique_id in
#{descUniqueId}
AND upload_time <= CONCAT(#{nowDate},' 23:59:59') GROUP BY date_format(upload_time, '%Y-%m-%d %H' ),unique_id ORDER BY upload_time desc ) b ON DATE_FORMAT(a.upload_time, '%Y-%m-%d %H') = b.hour_group AND a.upload_time = b.upload_time and `name` = 'impep' and a.unique_id = b.unique_id AND a.unique_id in
#{descUniqueId}
order by a.upload_time desc ) b
ON CONCAT(date_format(a.upload_time, '%Y-%m-%d %H' ),':00:00') = DATE_ADD(CONCAT(date_format(b.upload_time, '%Y-%m-%d %H' ),':00:00'), INTERVAL 1 HOUR) and a.unique_id = b.unique_id where DATE(a.upload_time) = #{nowDate}
) a GROUP BY a.`hour` order by a.`hour`

select sum(powerConsumption) totalLight,a.`month` from (
SELECT date_format(a.upload_time, '%m' ) `month`, ABS(a.`value` - b.`value`) AS powerConsumption,a.upload_time FROM ( select a.`name`,a.`value`,a.upload_time,a.unique_id from tunnel_power_data a JOIN ( select DATE_FORMAT(upload_time, '%Y-%m') AS hour_group,MAX(upload_time) upload_time,unique_id from tunnel_power_data where `name`='IMPEP' and upload_time >= CONCAT(DATE_SUB(concat(#{year},'-01-01'),INTERVAL 1 year),'-12-01') AND unique_id in
#{ascUniqueId}
AND upload_time <= CONCAT(#{year},'-12-31') GROUP BY date_format(upload_time, '%Y-%m' ),unique_id ORDER BY upload_time desc ) b ON DATE_FORMAT(a.upload_time, '%Y-%m') = b.hour_group AND a.upload_time = b.upload_time and `name` = 'impep' and a.unique_id = b.unique_id AND a.unique_id in
#{ascUniqueId}
AND DATE_FORMAT(a.upload_time, '%Y') = #{year} order by a.upload_time desc ) a JOIN ( select a.`name`,a.`value`,a.upload_time,a.unique_id from tunnel_power_data a JOIN ( select DATE_FORMAT(upload_time, '%Y-%m') AS hour_group,MAX(upload_time) upload_time,unique_id from tunnel_power_data where `name`='IMPEP' and upload_time >= CONCAT(DATE_SUB(concat(#{year},'-01-01'),INTERVAL 1 year),'-12-01') AND unique_id in
#{ascUniqueId}
AND upload_time <= CONCAT(#{year},'-12-31') GROUP BY date_format(upload_time, '%Y-%m' ),unique_id ORDER BY upload_time desc ) b ON DATE_FORMAT(a.upload_time, '%Y-%m') = b.hour_group AND a.upload_time = b.upload_time and `name` = 'impep' and a.unique_id = b.unique_id AND a.unique_id in
#{ascUniqueId}
order by a.upload_time desc ) b
ON CONCAT(date_format(a.upload_time, '%Y-%m'),'-01') = DATE_ADD(CONCAT(date_format(b.upload_time, '%Y-%m'),'-01'), INTERVAL 1 MONTH) and a.unique_id = b.unique_id ) a GROUP BY a.`month`
